+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {
+  end: number,
+  image: boolean,
+  label: string,
+  target: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown' || options.imageStyle === 'markdown') {
+      text = convertWikiToMarkdown(text, options);
+    }
+    if (options.linkStyle === 'wiki' || options.imageStyle === 'wiki') {
+      text = convertMarkdownToWiki(text, options);
+    }
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: dedent`
+          [[Page#Heading]]
+          [[Page|Display text]]
+          ![[image.png|300x200]]
+        `,
+        after: dedent`
+          [Page > Heading](Page#Heading)
+          [Display text](Page)
+          ![image.png](image.png)
+        `,
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert inline Markdown links and images to wiki links and embeds',
+        before: dedent`
+          [Page > Heading](Page#Heading)
+          ![description](image.png)
+        `,
+        after: dedent`
+          [[Page#Heading]]
+          ![[image.png|description]]
+        `,
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: styleRecords,
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records: styleRecords,
+      }),
+    ];
+  }
+}
+
+const styleRecords = [
+  {value: 'no-change' as const, description: 'Leave this link type unchanged'},
+  {value: 'markdown' as const, description: 'Use Markdown links and images'},
+  {value: 'wiki' as const, description: 'Use Obsidian wiki links and embeds'},
+];
+
+function convertWikiToMarkdown(text: string, options: LinkStyleOptions): string {
+  return text.replace(/(!?)\\[\\[([^\\]\
]*)\\]\\]/g, (match, embedIndicator: string, contents: string) => {
+    const image = embedIndicator === '!';
+    if ((image ? options.imageStyle : options.linkStyle) !== 'markdown') {
+      return match;
+    }
+
+    const separator = contents.indexOf('|');
+    const target = separator === -1 ? contents : contents.substring(0, separator);
+    let display = separator === -1 ? '' : contents.substring(separator + 1);
+    if (image && /^(?:\\d+|\\d+x\\d+)$/.test(display)) {
+      display = '';
+    }
+    display = display || defaultDisplay(target);
+    return image ? `![${display}](${target})` : `[${display}](${target})`;
+  });
+}
+
+function convertMarkdownToWiki(text: string, options: LinkStyleOptions): string {
+  let result = '';
+  let cursor = 0;
+  while (cursor < text.length) {
+    const link = parseMarkdownLink(text, cursor);
+    if (!link || (link.image ? options.imageStyle : options.linkStyle) !== 'wiki' || link.target.includes('://')) {
+      result += text[cursor++];
+      continue;
+    }
+
+    const omitDisplay = link.label === '' || link.label === link.target || link.label === defaultDisplay(link.target);
+    const display = omitDisplay ? '' : `|${link.label}`;
+    result += `${link.image ? '!' : ''}[[${link.target}${display}]]`;
+    cursor = link.end;
+  }
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = text[start] === '!' && text[start + 1] === '[';
+  const bracketStart = image ? start + 1 : start;
+  if (text[bracketStart] !== '[' || (start > 0 && text[start - 1] === '\\\')) {
+    return null;
+  }
+
+  const labelEnd = findClosingBracket(text, bracketStart);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const labelText = text.substring(bracketStart + 1, labelEnd);
+  if (labelText.includes('\
')) {
+    return null;
+  }
+
+  const destinationEnd = findClosingParenthesis(text, labelEnd + 1);
+  if (destinationEnd === -1) {
+    return null;
+  }
+  const destination = parseDestination(text.substring(labelEnd + 2, destinationEnd));
+  if (destination == null) {
+    return null;
+  }
+  return {end: destinationEnd + 1, image, label: unescapeMarkdown(labelText), target: destination};
+}
+
+function findClosingBracket(text: string, open: number): number {
+  let depth = 1;
+  for (let index = open + 1; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '[') {
+      depth++;
+    } else if (text[index] === ']' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function findClosingParenthesis(text: string, open: number): number {
+  let depth = 1;
+  for (let index = open + 1; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === '(') {
+      depth++;
+    } else if (text[index] === ')' && --depth === 0) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function parseDestination(value: string): string | null {
+  if (value.includes('\
')) {
+    return null;
+  }
+  const trimmed = value.trim();
+  if (trimmed.startsWith('<')) {
+    const closing = findUnescapedCharacter(trimmed, '>', 1);
+    if (closing === -1 || trimmed.substring(closing + 1).trim() !== '') {
+      return null;
+    }
+    return unescapeMarkdown(trimmed.substring(1, closing));
+  }
+  if (hasUnescapedWhitespace(trimmed)) {
+    return null;
+  }
+  return unescapeMarkdown(trimmed);
+}
+
+function findUnescapedCharacter(text: string, character: string, start: number): number {
+  for (let index = start; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (text[index] === character) {
+      return index;
+    }
+  }
+  return -1;
+}
+
+function hasUnescapedWhitespace(text: string): boolean {
+  for (let index = 0; index < text.length; index++) {
+    if (text[index] === '\\\') {
+      index++;
+    } else if (/\\s/.test(text[index])) {
+      return true;
+    }
+  }
+  return false;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultDisplay(target: string): string {
+  const heading = target.indexOf('#');
+  if (heading === -1) {
+    return target;
+  }
+  const page = target.substring(0, heading);
+  const section = target.substring(heading + 1);
+  return page ? `${page} > ${section}` : section;
+}
